const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!Array.isArray(body.disclosure_ids) || body.disclosure_ids.length === 0) return { json: { _empty: true, error: 'disclosure_ids[] required' } };
if (!body.client_email) return { json: { _empty: true, error: 'client_email required' } };
return { json: {
  _authorized: true,
  disclosure_ids: body.disclosure_ids,
  client_email: body.client_email,
  client_name: body.client_name || 'Client'
} };

const ctx = $('Per Disclosure').item.json;
const rows = $input.item.json;
const d = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!d || !d.id) return { json: { _missing: true, disclosure_id: ctx.disclosure_id } };
if (!d.document_url) return { json: { _missing: true, disclosure_id: ctx.disclosure_id, reason: 'no document_url on disclosure' } };
return { json: {
  disclosure_id: d.id,
  client_id: d.client_id,
  disclosure_type: d.disclosure_type,
  document_url: d.document_url,
  client_email: ctx.client_email,
  client_name: ctx.client_name
} };

const ctx = $('Build Zoho Body').item.json;
const resp = $input.item.json || {};
const req = (resp.requests && resp.requests[0]) || resp.requests || resp;
const envelopeId = (req && (req.request_id || req.id)) || null;
const signingUrl = (req && req.actions && req.actions[0] && req.actions[0].action_url) || null;
if (!envelopeId) return { json: { _failed: true, disclosure_id: ctx.disclosure_id, error: (resp.message || resp.status || 'no envelope id') } };
return { json: {
  disclosure_id: ctx.disclosure_id,
  envelope_id: envelopeId,
  signing_url: signingUrl,
  client_email: ctx.client_email,
  client_name: ctx.client_name,
  disclosure_type: ctx.disclosure_type,
  client_id: ctx.client_id
} };
